queries.sparql:
PREFIX : <http://ambrosia.example.org/agriculture#>
PREFIX p: <http://ambrosia.example.org/agriculture/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?componentname WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasComponents ?child ; p:hasFertilizers ?parent . } GROUP BY ?child }
  ?child p:name ?componentname .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Fertilizers } }
  FILTER(?nf = ?total)
}

ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/agriculture#>
PREFIX p: <http://ambrosia.example.org/agriculture/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE scope {
  collective: { SELECT ?componentname WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasComponents ?child ; p:hasFertilizers ?parent . } GROUP BY ?child }
  ?child p:name ?componentname .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Fertilizers } }
  FILTER(?nf = ?total)
} }
  distributive: { SELECT ?name ?componentname WHERE {
  ?fertilizers_components a :Fertilizers_Components .
  ?components a :Components .
  ?fertilizers_components p:hasComponents ?components .
  ?fertilizers a :Fertilizers .
  ?fertilizers_components p:hasFertilizers ?fertilizers .
  ?fertilizers p:name ?name .
  ?components p:name ?componentname .
} }
}
